INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('06b921acce773fc9d5879', 'Rexy-chan', 'Tyrannosaurus rex', 'Cretaceous', 'Late Cretaceous', 'Carnivore', 12.3, 8400, 'legendary', 'The undisputed queen of the dinosaurs. Rexy-chan rules with an iron jaw and a surprisingly gentle heart — when she''s not hungry, at least.', '["Had the strongest bite force of any land animal ever", "Could eat 230 kg of meat in a single bite", "Arms were actually quite muscular despite their size"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('948cb61dbae7e6b5bea3a', 'Tri-tan', 'Triceratops horridus', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 9.0, 6000, 'epic', 'Three horns, one enormous frill, and a heart of gold. Tri-tan charges headfirst into any problem — literally.', '["The frill may have been used for temperature regulation", "Lived alongside T. rex", "Had a beak like a parrot"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('93dceb99ae11326c2b94f', 'Velo-chan', 'Velociraptor mongoliensis', 'Cretaceous', 'Late Cretaceous', 'Carnivore', 2.0, 15, 'rare', 'Small, feathered, and dangerously clever. Velo-chan may look cute, but she''s already planned three escape routes and a ambush.', '["Was actually the size of a turkey", "Covered in feathers", "Had a sickle-shaped killing claw on each foot"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('162290ab40ff583160473', 'Stego-tan', 'Stegosaurus stenops', 'Jurassic', 'Late Jurassic', 'Herbivore', 9.0, 3100, 'epic', 'Her plates blush when she''s embarrassed, which is often. Stego-tan is shy but surprisingly fierce when cornered — that tail spike isn''t just decorative!', '["Brain was the size of a walnut", "Tail spikes are called a ''thagomizer''", "Plates may have changed color for communication"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2fd46fee17010880616be', 'Bronto-hime', 'Brontosaurus excelsus', 'Jurassic', 'Late Jurassic', 'Herbivore', 22.0, 15000, 'legendary', 'The gentle giant princess. Bronto-hime towers above everyone but speaks in the softest whisper. Her footsteps make the earth tremble with grace.', '["Was declared invalid for over a century before being reinstated", "Could crack its tail like a whip at supersonic speeds", "Swallowed stones to help digest food"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0e15d7874ccd5076e7d40', 'Pterry', 'Pteranodon longiceps', 'Cretaceous', 'Late Cretaceous', 'Piscivore', 1.8, 25, 'rare', 'Not technically a dinosaur, and she''ll correct you every time. Pterry soars above it all with her impressive 7-meter wingspan and sharp wit.', '["Wingspan up to 7 meters", "Males had a large crest on their heads", "Caught fish by skimming the ocean surface"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('b93aab5eb3f01fdd74c6f', 'Anky-chan', 'Ankylosaurus magniventris', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 6.25, 6000, 'epic', 'The ultimate defensive specialist. Anky-chan is covered head to tail in armor and carries a club that could shatter a T. rex''s ankle.', '["Tail club could swing with enough force to break bones", "Even its eyelids were armored", "Walked low to the ground like a tank"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9f1da2a89c1bf3afafabb', 'Parasol', 'Parasaurolophus walkeri', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 9.5, 2500, 'rare', 'Her hollow crest produces the most beautiful music in the Mesozoic. Parasol is the resident musician, humming ancient melodies that echo through the valleys.', '["Crest was used to produce sounds like a trombone", "Could walk on two or four legs", "Had hundreds of teeth for grinding plants"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8d2d6a354f29a724a74f4', 'Spino-sama', 'Spinosaurus aegyptiacus', 'Cretaceous', 'Late Cretaceous', 'Piscivore', 15.0, 7400, 'legendary', 'Larger than T. rex but prefers fishing to fighting. Spino-sama is the mysterious loner who wades through rivers at dawn, her magnificent sail catching the light.', '["Largest known carnivorous dinosaur", "Spent most of its time in water", "Had a sail on its back up to 1.7 meters tall"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2eaa4cbac5a71f5adb46c', 'Diplo-kun', 'Diplodocus longus', 'Jurassic', 'Late Jurassic', 'Herbivore', 25.0, 12000, 'epic', 'The longest noodle of the dinosaur world. Diplo-kun''s neck seems to go on forever, and he uses it to reach the tallest, tastiest treetops.', '["One of the longest dinosaurs ever", "Could crack its whip-like tail at supersonic speeds", "Had pencil-shaped teeth for stripping leaves"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('001ba030720b0583fdadb', 'Allo-san', 'Allosaurus fragilis', 'Jurassic', 'Late Jurassic', 'Carnivore', 8.5, 2300, 'rare', 'The apex predator of the Jurassic, but with surprisingly refined manners. Allo-san hunts with calculated elegance, not brute force.', '["Used its upper jaw like a hatchet", "Hunted in packs possibly", "Most common large predator of the Late Jurassic"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2d424bb39b8dbf6c85776', 'Brachy-chan', 'Brachiosaurus altithorax', 'Jurassic', 'Late Jurassic', 'Herbivore', 22.0, 56000, 'legendary', 'Her head literally lives in the clouds. Brachy-chan is a dreamer whose gentle gaze from 13 meters up makes everything seem small and peaceful.', '["Could raise its head to 13 meters high", "Front legs were longer than back legs", "Nostrils were on top of its head"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('73c2101cb11150082a6ac', 'Raptor-chan', 'Deinonychus antirrhopus', 'Cretaceous', 'Early Cretaceous', 'Carnivore', 3.4, 73, 'uncommon', 'The real-life inspiration for those movie raptors. Raptor-chan coordinates hunts with terrifying intelligence and questionable table manners.', '["Name means ''terrible claw''", "Revolutionized our understanding of dinosaur intelligence", "Likely hunted in coordinated groups"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ff5c151ba5f7d38c1bac0', 'Iggy', 'Iguanodon bernissartensis', 'Cretaceous', 'Early Cretaceous', 'Herbivore', 10.0, 3000, 'uncommon', 'One of the first dinosaurs ever discovered, and she''s very proud of it. Iggy gives a thumbs up with her signature spike — except that spike is actually on her thumb.', '["Second dinosaur ever to be named", "Thumb spike was once placed on its nose", "Could walk on two or four legs"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e3b12550114f2ac47e5a8', 'Compy', 'Compsognathus longipes', 'Jurassic', 'Late Jurassic', 'Carnivore', 0.65, 0.83, 'common', 'Tiny but absolutely fearless. Compy travels in a chaotic pack and will steal your lunch before you even notice she''s there.', '["One of the smallest known dinosaurs", "About the size of a chicken", "Was the first dinosaur found with evidence of its last meal"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('beb976161acead93ea06d', 'Plessy', 'Plesiosaurus dolichodeirus', 'Jurassic', 'Early Jurassic', 'Piscivore', 3.5, 450, 'rare', 'The original sea serpent legend. Plessy glides through ancient oceans with her impossibly long neck, always looking for the perfect fish.', '["Not a dinosaur \u2014 a marine reptile", "Inspired the Loch Ness Monster legend", "Gave birth to live young"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8e06e085e774aa8e506ce', 'Mossy', 'Mosasaurus hoffmannii', 'Cretaceous', 'Late Cretaceous', 'Carnivore', 13.0, 5000, 'legendary', 'Terror of the ancient seas. Mossy commands respect with a single glance from her massive jaws. Even sharks swim the other way.', '["Could grow up to 17 meters long", "Related to modern monitor lizards", "Dominated the oceans after ichthyosaurs went extinct"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6fca9014e8ce049aca94f', 'Ptera', 'Quetzalcoatlus northropi', 'Cretaceous', 'Late Cretaceous', 'Carnivore', 5.0, 250, 'legendary', 'The largest flying creature ever. Ptera stands as tall as a giraffe and spreads wings wider than a small airplane. She is majesty incarnate.', '["Wingspan of 10-11 meters", "As tall as a giraffe when standing", "Named after the Aztec feathered serpent god"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8a38a0445fb72578e4397', 'Ichthy-chan', 'Ichthyosaurus communis', 'Jurassic', 'Early Jurassic', 'Piscivore', 2.0, 90, 'uncommon', 'Looks like a dolphin, acts like a dolphin, but is definitely not a dolphin. Ichthy-chan evolved this shape 200 million years before dolphins thought of it.', '["Convergent evolution with dolphins", "Had the largest eyes relative to body size", "First discovered by Mary Anning"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c0a35a15db939e3630720', 'Megalo-chan', 'Megalosaurus bucklandii', 'Jurassic', 'Middle Jurassic', 'Carnivore', 6.0, 700, 'uncommon', 'The very first dinosaur ever named, and she wears that title like a crown. Megalo-chan walks with historic confidence.', '["First dinosaur ever to be scientifically described", "Named in 1824", "Originally thought to walk on four legs"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('fa561fb0dad8632def253', 'Archaeo', 'Archaeopteryx lithographica', 'Jurassic', 'Late Jurassic', 'Omnivore', 0.5, 0.8, 'epic', 'Half dinosaur, half bird, fully fabulous. Archaeo is the fashionista who proved dinosaurs could be beautiful AND fly. Sort of.', '["Considered the first bird", "Had teeth, clawed wings, and a bony tail", "Only about the size of a raven"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('72142fce5b2456d184b60', 'Dimetro', 'Dimetrodon grandis', 'Paleozoic', 'Early Permian', 'Carnivore', 3.5, 250, 'rare', 'Often mistaken for a dinosaur, but she''s actually closer to YOU than to any dinosaur. Dimetro rocks her sail with proto-mammalian pride.', '["Not a dinosaur \u2014 a synapsid more related to mammals", "Predates dinosaurs by 40 million years", "Sail was used for temperature regulation"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8d91db4c0a2f2add638b2', 'Sabertooth', 'Smilodon fatalis', 'Cenozoic', 'Pleistocene', 'Carnivore', 1.75, 280, 'epic', 'Those fangs aren''t just for show — Sabertooth is the ice age''s most elegant predator. She flashes her 28cm canines and the whole tundra goes quiet.', '["Canine teeth up to 28 cm long", "Could open its jaw 120 degrees", "Went extinct about 10,000 years ago"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('a7a243b0d225c69d82e21', 'Woolly-chan', 'Mammuthus primigenius', 'Cenozoic', 'Pleistocene', 'Herbivore', 3.5, 6000, 'epic', 'Cozy, fluffy, and surprisingly emotional. Woolly-chan remembers everything — every slight, every kindness, every tasty grass patch.', '["Had 15 cm of fat under the skin", "Tusks could be up to 4.2 meters long", "Some specimens preserved so well we found intact blood"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2093ebcc64f403e09b6dd', 'Pachy-kun', 'Pachycephalosaurus wyomingensis', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 4.5, 450, 'uncommon', 'Hard-headed in every sense. Pachy-kun solves disagreements the old-fashioned way — by headbutting. His skull is 25 cm of solid dome.', '["Skull dome was 25 cm thick", "May have used head-butting for dominance", "Only the skull has been found \u2014 body is mostly guesswork"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('20cf216b60edfb3664191', 'Galli-chan', 'Gallimimus bullatus', 'Cretaceous', 'Late Cretaceous', 'Omnivore', 6.0, 440, 'uncommon', 'The fastest dinosaur in the west. Galli-chan dashes everywhere at 60 km/h and can''t sit still for more than three seconds.', '["Could run up to 60 km/h", "Name means ''chicken mimic''", "Had a beak instead of teeth"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('cd08a4eaabb034d94ecc3', 'Carno-chan', 'Carnotaurus sastrei', 'Cretaceous', 'Late Cretaceous', 'Carnivore', 7.5, 1350, 'rare', 'Bull horns, tiny arms, and a bad attitude. Carno-chan is the punk rocker of the dinosaur world, charging first and asking questions never.', '["Only large predator with horns above its eyes", "Arms were even tinier than T. rex proportionally", "One of the fastest large theropods"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('553b44e80e9a0168bbe7d', 'Theriz', 'Therizinosaurus cheloniformis', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 10.0, 5000, 'epic', 'Imagine Edward Scissorhands but a dinosaur. Theriz has meter-long claws and uses them to trim trees, not fight — mostly.', '["Had the longest claws of any animal ever \u2014 up to 1 meter", "Was a herbivore despite looking terrifying", "Related to velociraptors"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('bdc33468cbbacc15f0a77', 'Megane', 'Meganeura monyi', 'Paleozoic', 'Carboniferous', 'Carnivore', 0.65, 0.15, 'rare', 'A dragonfly with a 70 cm wingspan. Megane buzzes through Carboniferous forests hunting smaller insects, her iridescent wings catching ancient sunlight.', '["Wingspan of about 70 cm", "Existed 300 million years ago", "Could grow so large because oxygen levels were 35%"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('b1dd5e246671097501d8c', 'Arthro', 'Arthropleura armata', 'Paleozoic', 'Carboniferous', 'Herbivore', 2.3, 50, 'rare', 'A millipede the size of a car. Arthro is actually very gentle, munching peacefully on rotting wood in steamy Carboniferous forests.', '["Largest land invertebrate ever", "Up to 2.3 meters long", "Lived in the coal swamp forests 300 million years ago"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f16fae5af342a3e4dff6d', 'Dunky', 'Dunkleosteus terrelli', 'Paleozoic', 'Late Devonian', 'Carnivore', 6.0, 1000, 'epic', 'An armored fish with jaws that could snap steel. Dunky ruled the Devonian seas 360 million years ago with bone-crushing authority.', '["One of the first apex predators", "Had bony plates instead of teeth", "Bite force estimated at 6,000 newtons"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5c526097fcdc46eb4c220', 'Trilobi-chan', 'Paradoxides davidis', 'Paleozoic', 'Cambrian', 'Omnivore', 0.4, 0.5, 'common', 'One of the earliest complex creatures, and she knows it. Trilobi-chan has been rolling up into a ball to avoid problems since before it was cool — 500 million years before.', '["Trilobites existed for 300 million years", "Had some of the first complex eyes", "Could roll into a ball for defense like a pill bug"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('492a59e25d7a9ade2da3e', 'Ammonite-chan', 'Ammonoidea sp.', 'Mesozoic', 'Various', 'Carnivore', 0.3, 1.0, 'common', 'The spiral beauty of the ancient seas. Ammonite-chan''s shell is a perfect golden ratio, and she''s not above bragging about it.', '["Existed for over 350 million years", "Related to modern nautilus", "Shell follows the golden ratio spiral"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c51e42a8e78fb6a554ecd', 'Anomalo-chan', 'Anomalocaris canadensis', 'Paleozoic', 'Cambrian', 'Carnivore', 1.0, 5.0, 'rare', 'The apex predator of the Cambrian explosion. When everything else was tiny, Anomalo-chan was the one-meter monster that ruled them all.', '["Largest predator of the Cambrian period", "Had compound eyes with 16,000 lenses", "Used frontal appendages to catch prey"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('59abf5a0a8600213c04f7', 'Dilopho', 'Dilophosaurus wetherilli', 'Jurassic', 'Early Jurassic', 'Carnivore', 7.0, 400, 'uncommon', 'Crowned with twin crests, Dilopho struts through Early Jurassic landscapes like a runway model. She does NOT spit venom — that was movie slander.', '["Did NOT have a frill or spit venom", "Had two distinctive crests on its head", "One of the earliest large predatory dinosaurs"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('14f9eb6c1011af8317f1d', 'Coel', 'Coelophysis bauri', 'Triassic', 'Late Triassic', 'Carnivore', 3.0, 25, 'common', 'One of the earliest dinosaurs and still a crowd favorite. Coel is light, fast, and runs in packs — the original squad goals.', '["One of the earliest known dinosaurs", "Hollow bones made it very lightweight", "Hundreds found together suggesting pack behavior"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('48b2061a3dff8f81461dc', 'Plateosaurus', 'Plateosaurus engelhardti', 'Triassic', 'Late Triassic', 'Herbivore', 8.0, 600, 'uncommon', 'The first really big dinosaur. Plateosaurus proved that going big was the winning strategy, setting the stage for the giants that followed.', '["One of the first large dinosaurs", "Could stand on two legs to reach high plants", "Found all across Europe"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('1ad5c66381f1e8d07f920', 'Herrera', 'Herrerasaurus ischigualastensis', 'Triassic', 'Late Triassic', 'Carnivore', 3.5, 210, 'uncommon', 'From the very dawn of dinosaurs. Herrera is ancient even by dinosaur standards, and she carries that primordial energy with pride.', '["One of the oldest known dinosaurs", "Lived about 231 million years ago", "Found in Argentina"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('1760e0ae11488885deaa8', 'Euoplo', 'Euoplocephalus tutus', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 6.0, 2500, 'uncommon', 'Like Anky-chan''s shy cousin. Euoplo is armored from snout to tail club, but underneath all that plate mail is a gentle soul who just wants to munch ferns.', '["Even its eyelids had bony armor", "Tail club weighed about 30 kg", "Named ''well-armored head''"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c60f619101bf1c709a58d', 'Maiasaura', 'Maiasaura peeblesorum', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 9.0, 4000, 'uncommon', 'The ''good mother lizard.'' Maiasaura builds the coziest nests and cares for her babies with unmatched devotion. Community parenting goals.', '["Name means ''good mother lizard''", "First dinosaur found with evidence of parental care", "Nested in large colonies"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9ae3bce648d80de4a9dc4', 'Oviraptor', 'Oviraptor philoceratops', 'Cretaceous', 'Late Cretaceous', 'Omnivore', 1.6, 33, 'common', 'Falsely accused of egg theft for decades! Oviraptor was actually protecting her OWN eggs. She demands a formal apology from science.', '["Name means ''egg thief'' but was actually protecting its own eggs", "Had a distinctive crest on its head", "Closely related to birds"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('20d1df9c1e53aeab3c462', 'Corytho', 'Corythosaurus casuarius', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 9.0, 4000, 'uncommon', 'Wears her helmet-shaped crest with pride. Corytho''s honking calls can be heard across the valley — she''s the town crier of the Cretaceous.', '["Crest shaped like a Corinthian helmet", "Crest was hollow and used for sound", "Found with preserved skin impressions"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('083d915680bcfdd77d437', 'Lambeosaur', 'Lambeosaurus lambei', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 9.4, 5600, 'uncommon', 'The hatchet-crested hadrosaur. Lambeosaur''s distinctive forward-pointing crest makes her look perpetually ready for battle, but she''d rather be foraging.', '["Had a distinctive hatchet-shaped crest", "Could produce deep resonating sounds", "One of the largest hadrosaurs"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('88fabf0c764b82844bfad', 'Kentro', 'Kentrosaurus aethiopicus', 'Jurassic', 'Late Jurassic', 'Herbivore', 4.5, 700, 'common', 'Stego-tan''s spikier African cousin. Kentro traded plates for spikes and isn''t afraid to use them. Touch at your own risk.', '["Had spikes instead of plates on its back half", "Shoulder spikes up to 60 cm long", "Found in Tanzania"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('eab44f2797e7a99fb16af', 'Giganoto', 'Giganotosaurus carolinii', 'Cretaceous', 'Late Cretaceous', 'Carnivore', 12.0, 6800, 'legendary', 'South America''s answer to T. rex. Giganoto hunted sauropods in coordinated packs, combining brains and brawn in devastating fashion.', '["Slightly longer than T. rex", "Had a thinner skull and weaker bite", "Likely hunted in groups to take down titanosaurs"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('1b6d19271ac6144bfe342', 'Carcharo', 'Carcharodontosaurus saharicus', 'Cretaceous', 'Late Cretaceous', 'Carnivore', 12.0, 6200, 'epic', 'Named after the great white shark for her serrated teeth. Carcharo ruled North Africa with razor-sharp precision and an intimidating smile.', '["Name means ''shark-toothed lizard''", "Teeth were up to 20 cm long", "Lived in the same region as Spinosaurus"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('d1173169dd018a123dcea', 'Microraptor', 'Microraptor gui', 'Cretaceous', 'Early Cretaceous', 'Carnivore', 0.77, 1.0, 'rare', 'Four wings! FOUR WINGS! Microraptor is the glittery biplane of the dinosaur world, swooping through forests with iridescent black feathers.', '["Had flight feathers on all four limbs", "Feathers were iridescent black like a crow", "Glided between trees"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2f7702d3e73f5056a7631', 'Yutyrannus', 'Yutyrannus huali', 'Cretaceous', 'Early Cretaceous', 'Carnivore', 9.0, 1400, 'rare', 'The beautiful feathered tyrant. Yutyrannus proves that even 9-meter predators can be fluffy. She''s proud of every single feather.', '["Largest known feathered dinosaur", "Name means ''beautiful feathered tyrant''", "Covered in filamentous feathers"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('01147e6c4c428ffeb88a8', 'Titano', 'Titanosaurus indicus', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 12.0, 13000, 'uncommon', 'One of the armored titans. Titano may not be the biggest sauropod, but her osteoderms make her the toughest. Size AND armor? Unfair.', '["Had bony armor called osteoderms", "Part of a huge group of sauropods called titanosaurs", "Found on every continent"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ecc3c998513d4eb3d3417', 'Argento', 'Argentinosaurus huinculensis', 'Cretaceous', 'Late Cretaceous', 'Herbivore', 35.0, 70000, 'legendary', 'The heavyweight champion of ALL TIME. Argento is so massive that every step is an earthquake. She''s gentle though — just watch where you stand.', '["May have weighed up to 100 tonnes", "One of the largest land animals ever", "A single vertebra was 1.59 meters wide"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('7953e9585b3fe373132e0', 'Terror Bird', 'Phorusrhacos longissimus', 'Cenozoic', 'Miocene', 'Carnivore', 2.5, 130, 'rare', 'After the dinosaurs fell, Terror Bird rose. She''s a massive flightless predator who proves that birds are dinosaurs — the angry kind.', '["Stood over 2.5 meters tall", "Could not fly but ran extremely fast", "Dominated South America for millions of years"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('255eda55daf6cc9ec52c7', 'Megatherium', 'Megatherium americanum', 'Cenozoic', 'Pleistocene', 'Herbivore', 6.0, 4000, 'epic', 'A sloth the size of an elephant. Megatherium proves that being slow doesn''t mean being small. She reaches up to strip trees bare, one lazy bite at a time.', '["Could stand on hind legs to reach 6 meters", "Had claws up to 30 cm long", "One of the largest land mammals ever"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('fb877ca85386b4716ee41', 'Glyptodon', 'Glyptodon clavipes', 'Cenozoic', 'Pleistocene', 'Herbivore', 3.3, 2000, 'rare', 'Imagine an armadillo the size of a VW Beetle. Glyptodon trundles along inside her massive dome shell, impervious to basically everything.', '["Shell was made of over 1,000 bony plates", "Related to modern armadillos", "Humans may have used their shells as shelters"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6df23c7e0c56737ab70bb', 'Basilosaurus', 'Basilosaurus cetoides', 'Cenozoic', 'Eocene', 'Carnivore', 18.0, 5000, 'epic', 'The serpent of the ancient seas, except she''s actually a whale. Basilosaurus''s 18-meter body undulates through warm Eocene oceans like a living legend.', '["Not a reptile \u2014 an early whale", "Name means ''king lizard'' due to mistaken identity", "Still had tiny hind legs"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9d4d48ee5520774af3515', 'Megalodon', 'Otodus megalodon', 'Cenozoic', 'Miocene', 'Carnivore', 15.0, 50000, 'legendary', 'THE ultimate ocean predator. Megalodon''s jaws could swallow a great white shark whole. She''s the reason the deep ocean still scares us.', '["Teeth were up to 18 cm long", "Could bite with 108,000-182,000 newtons of force", "Went extinct about 3.6 million years ago"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('002657e553f794dca683e', 'Thalasso', 'Thalassomedon haningtoni', 'Cretaceous', 'Late Cretaceous', 'Piscivore', 12.0, 2000, 'rare', 'A plesiosaur with a neck so long it defies physics. Thalasso means ''sea lord,'' and she earned every letter of that name.', '["Neck was 6 meters long", "Had 62 cervical vertebrae", "Swallowed stones for ballast"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('d260660b9cdcebd4e6c90', 'Archie', 'Archelon ischyros', 'Cretaceous', 'Late Cretaceous', 'Omnivore', 4.6, 2200, 'rare', 'The biggest sea turtle ever. Archie cruised Cretaceous seas with the calm confidence of someone who knows they''re carrying 2 tonnes of shell.', '["Largest sea turtle ever known", "Leathery shell rather than hard", "Wingspan of flippers was 4 meters"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('39eae41eb01380c18a80d', 'Sarco', 'Sarcosuchus imperator', 'Cretaceous', 'Early Cretaceous', 'Carnivore', 11.0, 4500, 'epic', 'Super Croc. Sarco is twice the length of any modern crocodile and ten times the attitude. She''s patient, ancient, and absolutely terrifying.', '["Twice the length of any living crocodile", "Could take down dinosaurs", "Had a bulbous growth on the tip of its snout"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('20c8c6f8d9d68645b928e', 'Elasmosaur', 'Elasmosaurus platyurus', 'Cretaceous', 'Late Cretaceous', 'Piscivore', 14.0, 2000, 'epic', '72 neck vertebrae. SEVENTY-TWO. Elasmosaur has the longest neck of any animal ever, and she uses every centimeter to snatch fish from impossible angles.', '["Had 72 cervical vertebrae", "Total length up to 14 meters", "Originally reconstructed with the head on the wrong end"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('a2fbf311fcf132b485355', 'Lioplo', 'Liopleurodon ferox', 'Jurassic', 'Middle Jurassic', 'Carnivore', 6.0, 1700, 'rare', 'A pliosaur with jaws built for crushing. Lioplo was the apex predator of Jurassic oceans — compact, powerful, and utterly lethal.', '["Often exaggerated in media \u2014 was about 6 meters, not 25", "Had four powerful flippers for fast swimming", "Teeth were 30 cm long"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('62ae7364074ade3ff8ae5', 'Nothosaur', 'Nothosaurus giganteus', 'Triassic', 'Middle Triassic', 'Piscivore', 4.0, 200, 'common', 'An early marine reptile testing the waters — literally. Nothosaur splits her time between land and sea, not yet fully committed to ocean life.', '["Could live on land and in water", "Ancestor of plesiosaurs", "Had webbed feet"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('fd0df697f5670a99b6b02', 'Scutosaur', 'Scutosaurus karpinskii', 'Paleozoic', 'Late Permian', 'Herbivore', 3.0, 500, 'common', 'A tank before tanks existed. Scutosaur is a bulky Permian pareiasaur covered in bony studs, lumbering through ancient landscapes with zero worries.', '["Covered in bony armor plates", "One of the largest Permian land animals", "Related to the ancestors of turtles"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('732348007567590971011', 'Edaphosaur', 'Edaphosaurus pogonias', 'Paleozoic', 'Early Permian', 'Herbivore', 3.5, 300, 'common', 'Dimetro''s peaceful cousin. Edaphosaur has a similar sail but is a chill herbivore who''d rather sunbathe than hunt. Solar-powered since 300 million years ago.', '["Sail had cross-bars unlike Dimetrodon", "One of the first large herbivores", "Sail was likely used for thermoregulation"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ef2ebf8b7d371083642a5', 'Hallucigenia', 'Hallucigenia sparsa', 'Paleozoic', 'Cambrian', 'Omnivore', 0.03, 0.001, 'common', 'So weird scientists literally named her after a hallucination. Hallucigenia walks on spindly legs with spines on her back — or is it the other way around?', '["Scientists originally reconstructed it upside down", "Only about 3 cm long", "Has been flipped and reinterpreted multiple times"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('67a94f428341aca1176c4', 'Opabinia', 'Opabinia regalis', 'Paleozoic', 'Cambrian', 'Carnivore', 0.07, 0.01, 'uncommon', 'Five eyes and a backward-facing mouth on a trunk. When Opabinia was first presented at a conference, the audience literally laughed. She''s had the last laugh for 505 million years.', '["Had five eyes", "Proboscis pointed forward then curved down to its mouth", "Its presentation caused an audience of scientists to burst out laughing"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('d9875d74f19d0146ba240', 'Wiwaxia', 'Wiwaxia corrugata', 'Paleozoic', 'Cambrian', 'Herbivore', 0.05, 0.005, 'common', 'A spiky armored slug from the Cambrian. Wiwaxia crawls along the seafloor bristling with protective spines, looking like a tiny punk rock pincushion.', '["Covered in overlapping scales and long spines", "Only about 5 cm long", "Relationship to other animals is still debated"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('10c5d62d87fbb2fdf23f0', 'Tiktaalik', 'Tiktaalik roseae', 'Paleozoic', 'Late Devonian', 'Carnivore', 2.7, 30, 'epic', 'The fish that decided to go for a walk. Tiktaalik is THE transitional fossil between fish and land animals. She took the first steps so you could take yours.', '["Had both fish and tetrapod features", "Could do push-ups with its fins", "Found exactly where scientists predicted it would be"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('4b1b23cfa5bb158bb2c4b', 'Gorgono', 'Gorgonops torvus', 'Paleozoic', 'Late Permian', 'Carnivore', 2.5, 200, 'uncommon', 'Saber-toothed and synapsid, Gorgono predates cats by 250 million years but had the same idea about giant fangs. An ancient proto-mammal with serious bite.', '["Not a dinosaur \u2014 a therapsid (proto-mammal)", "Had large saber-like canine teeth", "Apex predator of the Late Permian"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('666beaab57e56943e2917', 'Diictodon', 'Diictodon feliceps', 'Paleozoic', 'Late Permian', 'Herbivore', 0.45, 2.0, 'common', 'The tiny burrowing dicynodont with a beak and tusks. Diictodon is basically a prehistoric hamster that dug elaborate tunnel networks. Community housing pioneer.', '["Lived in elaborate burrow systems", "Had a beak like a turtle", "One of the most common Permian vertebrates"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('d8efff19fee494e3f4bc6', 'Kaprosuchus', 'Kaprosuchus saharicus', 'Cretaceous', 'Late Cretaceous', 'Carnivore', 6.0, 800, 'rare', 'Nicknamed ''BoarCroc'' for good reason. Kaprosuchus had massive tusks, long legs, and could gallop. Imagine a crocodile that chases you on land. Sleep tight.', '["Could gallop on land", "Had large boar-like tusks", "Nicknamed ''BoarCroc''"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0ce7dfa0f699faf39a445', 'Quinkana', 'Quinkana fortirostrum', 'Cenozoic', 'Pleistocene', 'Carnivore', 6.0, 500, 'uncommon', 'Australia''s land-running crocodile. Because of course Australia had those. Quinkana terrorized the outback on long legs until just 40,000 years ago.', '["A fully terrestrial crocodile", "Had blade-like teeth for cutting", "Coexisted with early humans in Australia"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f2d60f0bbadb61778ec14', 'Thylacosmilus', 'Thylacosmilus atrox', 'Cenozoic', 'Miocene', 'Carnivore', 1.2, 100, 'rare', 'A marsupial saber-tooth! Thylacosmilus independently evolved giant fangs just like Smilodon, proving that evolution really likes putting big teeth on things.', '["Not related to cats \u2014 a marsupial", "Fangs grew continuously throughout life", "Convergent evolution with saber-toothed cats"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('4f17c08268e7f9c578af6', 'Andrewsarchus', 'Andrewsarchus mongoliensis', 'Cenozoic', 'Eocene', 'Omnivore', 3.4, 1000, 'epic', 'The largest terrestrial mammalian predator ever. Andrewsarchus is known from a single massive skull and the nightmares it inspired. Related to sheep, somehow.', '["Known only from a single 83 cm skull", "Possibly related to hippos and whales", "Largest known mammalian land predator"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0a219acbffbcfdcfa0768', 'Paraceratherium', 'Paraceratherium transouralicum', 'Cenozoic', 'Oligocene', 'Herbivore', 7.4, 15000, 'legendary', 'The largest land mammal EVER. Paraceratherium was a hornless rhino that stood taller than a giraffe. She grazes the treetops with prehistoric elegance.', '["Largest land mammal ever known", "Stood about 5 meters at the shoulder", "Weighed as much as 4 elephants"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('303b840e7b77d2b6fb1c6', 'Doedicurus', 'Doedicurus clavicaudatus', 'Cenozoic', 'Pleistocene', 'Herbivore', 4.0, 1500, 'uncommon', 'Glyptodon''s cousin with a spiked club tail. Doedicurus is what happens when an armadillo maxes out both defense AND offense. Nature''s medieval knight.', '["Had a spiked club on its tail", "Related to modern armadillos", "Shell could be 1.5 meters across"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('53017909764d7770114ba', 'Elasmotherium', 'Elasmotherium sibiricum', 'Cenozoic', 'Pleistocene', 'Herbivore', 5.0, 5000, 'epic', 'The Siberian Unicorn. A massive rhino with a single enormous horn, Elasmotherium thundered across the steppe until just 29,000 years ago. Unicorns were real — just fluffier.', '["May have inspired unicorn legends", "Horn estimated at 1 meter long", "Survived until relatively recently \u2014 29,000 years ago"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6a5d61a205e6ddbde7221', 'Diprotodon', 'Diprotodon optatum', 'Cenozoic', 'Pleistocene', 'Herbivore', 3.0, 2800, 'rare', 'The largest marsupial ever. Diprotodon was basically a hippo-sized wombat that roamed Australia. She''s the OG big girl of the outback.', '["Largest marsupial ever", "About the size of a hippopotamus", "Went extinct about 44,000 years ago"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ff53621a5084d98725dd3', 'Thylacoleo', 'Thylacoleo carnifex', 'Cenozoic', 'Pleistocene', 'Carnivore', 1.5, 130, 'rare', 'The marsupial lion of Australia. Despite being related to kangaroos and wombats, Thylacoleo had the strongest bite force relative to body size of any mammal. Ever.', '["Strongest bite of any mammal relative to size", "Had retractable claws like a cat", "Was a marsupial despite being lion-like"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('3f2a2017e4abb67c59072', 'Dodo-chan', 'Raphus cucullatus', 'Cenozoic', 'Holocene', 'Herbivore', 1.0, 17.5, 'common', 'Yes, she''s a meme. But Dodo-chan was perfectly adapted to her island paradise — it''s not her fault humans showed up. She demands respect.', '["Went extinct in 1662", "Had no natural predators on Mauritius", "Not actually stupid \u2014 just unafraid of humans"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e9619a98955ac222e38d7', 'Tanystropheus', 'Tanystropheus longobardicus', 'Triassic', 'Middle Triassic', 'Piscivore', 6.0, 150, 'uncommon', 'Half of her length is just neck. Tanystropheus looks like nature was experimenting with proportions and went a bit too far. She doesn''t mind — more reach for fishing.', '["Neck was longer than body and tail combined", "Neck had only 13 enormously elongated vertebrae", "Likely fished from the shoreline"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('a4503d43e27981223ee1b', 'Sharovipteryx', 'Sharovipteryx mirabilis', 'Triassic', 'Late Triassic', 'Insectivore', 0.24, 0.01, 'common', 'A tiny gliding reptile with wings on its LEGS. Sharovipteryx looks like evolution tried to make a biplane but put the wings in the wrong spot.', '["Had membranes between its hind legs for gliding", "Only about 24 cm long", "One of the earliest known gliding reptiles"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f06ec470348983c545060', 'Longisquama', 'Longisquama insignis', 'Triassic', 'Middle Triassic', 'Insectivore', 0.15, 0.01, 'common', 'Sports a row of bizarre elongated scales along her back that look like feathered hockey sticks. What were they for? Nobody knows. Fashion, probably.', '["Had long bizarre scales along its back", "Their function is still debated", "Very small \u2014 about 15 cm long"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f64b722101fc7b371eda5', 'Postosuchus', 'Postosuchus kirkpatricki', 'Triassic', 'Late Triassic', 'Carnivore', 4.0, 250, 'uncommon', 'The apex predator before dinosaurs took over. Postosuchus was a massive croc-relative that walked upright and ruled the Late Triassic landscape.', '["Related to crocodiles, not dinosaurs", "Could walk on two legs", "Apex predator before dinosaurs dominated"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f033504f8e9239e47e26a', 'Desmatosuchus', 'Desmatosuchus spurensis', 'Triassic', 'Late Triassic', 'Herbivore', 5.0, 300, 'common', 'A heavily armored aetosaur that looks like a crocodile cosplaying as a stegosaurus. Desmatosuchus has shoulder spikes, back plates, and zero tolerance for predators.', '["Had massive shoulder spikes", "An aetosaur \u2014 related to crocodilians", "Covered in bony armor plates called osteoderms"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2d79eb0e95678d0a2852b', 'Nyasasaurus', 'Nyasasaurus parringtoni', 'Triassic', 'Middle Triassic', 'Omnivore', 2.0, 60, 'rare', 'Possibly the very first dinosaur, or the closest thing to it. Nyasasaurus walked the earth 243 million years ago, before dinosaurs were even a proper thing.', '["May be the oldest known dinosaur or dinosaur relative", "Lived 243 million years ago", "Known from fragmentary remains"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('30a93e6d964e970d6006e', 'Helicoprion', 'Helicoprion davisii', 'Paleozoic', 'Early Permian', 'Carnivore', 4.0, 200, 'rare', 'A shark with a tooth spiral that looks like a circular saw. Scientists debated where the whorl went for a century. Answer: in the lower jaw, like a nightmare buzzsaw.', '["Had a spiral of teeth called a tooth whorl", "Scientists argued for 100+ years where the whorl went", "Not technically a shark \u2014 a related fish"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('44cab61385d17bb1dda1e', 'Cameroceras', 'Cameroceras trentonense', 'Paleozoic', 'Ordovician', 'Carnivore', 6.0, 200, 'uncommon', 'A nautiloid so big it terrorized the entire Ordovician ocean. Cameroceras had a cone-shaped shell up to 6 meters long. The original sea monster.', '["One of the largest Ordovician creatures", "A relative of modern nautilus", "Shell could be up to 6 meters long"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('3be414611ffde1303b85b', 'Eurypterus', 'Eurypterus remipes', 'Paleozoic', 'Silurian', 'Carnivore', 0.25, 0.5, 'common', 'A sea scorpion — and yes, some grew to 2.5 meters. Eurypterus herself is smaller but still represents the terrifying age when arthropods ruled the seas.', '["A sea scorpion", "Some relatives grew up to 2.5 meters", "State fossil of New York"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('b37784633a551e4bfd308', 'Acanthostega', 'Acanthostega gunnari', 'Paleozoic', 'Late Devonian', 'Carnivore', 0.6, 2.0, 'uncommon', 'One of the first vertebrates with proper limbs — but she still had gills and a fish tail. Acanthostega is evolution caught mid-thought.', '["Had eight fingers on each hand", "Still had gills despite having legs", "Key transitional fossil between fish and tetrapods"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('dbd8546f55ae87cc584be', 'Dunkleosteus Jr.', 'Titanichthys agassizi', 'Paleozoic', 'Late Devonian', 'Omnivore', 5.0, 600, 'uncommon', 'Unlike her cousin Dunky, Titanichthys was a gentle giant filter feeder — the whale shark of the Devonian. All that armor and she just wanted plankton.', '["An armored fish like Dunkleosteus but a filter feeder", "Up to 5 meters long", "Had no sharp bony blades \u2014 fed on small organisms"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8e19a9e7c7cb85b2ffbf3', 'Cooksonia', 'Cooksonia barrandei', 'Paleozoic', 'Silurian', 'Photosynthetic', 0.06, 0.001, 'common', 'Not an animal — one of the first land plants! Cooksonia is a tiny fork-shaped pioneer who made dry land livable for everyone else. The ultimate support character.', '["One of the earliest known land plants", "Only about 6 cm tall", "Made colonization of land possible for animals"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9f9d5982ad3d16088c241', 'Aegirocassis', 'Aegirocassis benmoulai', 'Paleozoic', 'Ordovician', 'Herbivore', 2.0, 20, 'rare', 'A giant filter-feeding anomalocarid. Aegirocassis swam through Ordovician seas like a prehistoric whale shark, peacefully filtering plankton with modified appendages.', '["A gentle giant filter feeder", "Related to the predatory Anomalocaris", "Had paired flaps for swimming"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6149e77319d63f2ed4e08', 'Lystrosaurus', 'Lystrosaurus murrayi', 'Triassic', 'Early Triassic', 'Herbivore', 1.0, 100, 'common', 'The ultimate survivor. After the Great Dying wiped out 96% of all species, Lystrosaurus was one of the few left standing. She once made up 95% of all land vertebrates.', '["Survived the worst mass extinction in history", "At one point 95% of all land vertebrates were Lystrosaurus", "Found on every continent including Antarctica"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9f0de63532b00cf3afe4b', 'Ambulocetus', 'Ambulocetus natans', 'Cenozoic', 'Eocene', 'Carnivore', 3.0, 300, 'uncommon', 'The ''walking whale.'' Ambulocetus is the missing link between land mammals and whales — she walked AND swam, ambushing prey like a crocodile.', '["Name means ''walking whale''", "Could walk on land and swim", "Key transitional fossil in whale evolution"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f6acaebcc3fbcd84980aa', 'Pakicetus', 'Pakicetus inachus', 'Cenozoic', 'Eocene', 'Carnivore', 1.0, 25, 'common', 'A tiny wolf-like creature that would one day become... a whale? Pakicetus is proof that evolution''s plans are wilder than any fiction.', '["Earliest known whale ancestor", "Looked like a small dog or wolf", "Lived on land near the shore"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('96d3d4b393478c0e28380', 'Sivatherium', 'Sivatherium giganteum', 'Cenozoic', 'Pleistocene', 'Herbivore', 3.0, 1200, 'uncommon', 'The moose of giraffes. Sivatherium had massive antler-like ossicones and a stocky build. She looked like a giraffe designed by a committee that included moose.', '["Related to giraffes but much stockier", "Had large antler-like ossicones", "Survived until about 8,000 years ago"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e3387b189eade07f8393b', 'Deinotherium', 'Deinotherium giganteum', 'Cenozoic', 'Miocene', 'Herbivore', 5.0, 14000, 'epic', 'An elephant with its tusks pointing DOWN from the lower jaw. Deinotherium is what happens when evolution says ''what if we put those the other way round?''', '["Tusks curved downward from the lower jaw", "One of the largest land mammals ever", "Name means ''terrible beast''"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('07c7d34cfc8f5e02321c8', 'Josephoartigasia', 'Josephoartigasia monesi', 'Cenozoic', 'Pliocene', 'Herbivore', 3.0, 1000, 'rare', 'The largest rodent ever. Josephoartigasia was a capybara the size of a buffalo. If you think modern capybaras are chill, imagine this absolute unit.', '["Largest rodent ever known", "About the size of a buffalo", "Related to modern guinea pigs and capybaras"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9c1e69bccc04b0d4a59a7', 'Arctodus', 'Arctodus simus', 'Cenozoic', 'Pleistocene', 'Omnivore', 3.4, 800, 'rare', 'The short-faced bear — taller than a grizzly and built for speed. Arctodus could outrun a horse and stood 3.4 meters on hind legs. Peak bear performance.', '["Could stand 3.4 meters tall on hind legs", "Built for speed unlike modern bears", "One of the largest land carnivores in ice age North America"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f05e044c4517283039aa3', 'Procoptodon', 'Procoptodon goliah', 'Cenozoic', 'Pleistocene', 'Herbivore', 2.0, 230, 'uncommon', 'A kangaroo the size of a gorilla with a flat face. Procoptodon couldn''t hop like modern roos — she walked upright like a short, furry, confused person.', '["Largest kangaroo ever", "Could not hop \u2014 walked instead", "Had a shortened flat face unlike modern kangaroos"]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('cd40926c17c4002acda1a', 'Megalania', 'Varanus priscus', 'Cenozoic', 'Pleistocene', 'Carnivore', 5.5, 600, 'epic', 'A 5-meter venomous monitor lizard. Megalania was basically a Komodo dragon supersized. She ruled prehistoric Australia with terrifying efficiency.', '["Largest venomous animal ever", "Related to Komodo dragons", "Coexisted with early Aboriginal Australians"]', NULL);
INSERT INTO banner (id, name, description, starts_at, is_active) VALUES ('ee685f8bea005b96192c8', 'Mesozoic Mayhem', 'All prehistoric creatures available!', 0, 1);
